import{_ as i,o as a,c as t,ag as o}from"./chunks/framework.DWeTidJA.js";const p=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1774637702000}'),l={name:"changelog.md"};function r(n,e,s,d,c,u){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="unreleased" tabindex="-1">[Unreleased] <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h2 id="_0-1-0-beta-2-2026-03-27" tabindex="-1">[0.1.0-beta.2] - 2026-03-27 <a class="header-anchor" href="#_0-1-0-beta-2-2026-03-27" aria-label="Permalink to &quot;[0.1.0-beta.2] - 2026-03-27&quot;">​</a></h2><h3 id="🔒-security" tabindex="-1">🔒 Security <a class="header-anchor" href="#🔒-security" aria-label="Permalink to &quot;🔒 Security&quot;">​</a></h3><ul><li><strong>Removed <code>jade</code> dependency</strong> — was a direct production dependency but completely unused. Eliminated 4 CVEs it carried transitively: <code>constantinople</code> (critical — sandbox bypass/RCE), <code>uglify-js</code> (critical — ReDoS), <code>clean-css</code> (moderate — ReDoS), <code>transformers</code> (high — ReDoS)</li><li><strong>Upgraded <code>http-proxy-middleware</code> <code>^2.0.6</code> → <code>^3.0.5</code></strong> — removes the vulnerable <code>picomatch@2.3.1</code> transitive path. <strong>Breaking change handled:</strong> proxy event handlers migrated from top-level <code>onProxyReq</code>/<code>onProxyRes</code>/<code>onError</code> to nested <code>on: { proxyReq, proxyRes, error }</code> (v3 API)</li><li><strong>Upgraded <code>morgan</code> <code>~1.9.1</code> → <code>~1.10.1</code></strong> — fixes <code>on-headers</code> HTTP response header manipulation vulnerability (CVE GHSA-76c9-3jph-rj3q)</li><li><strong>Added <code>overrides</code></strong> in <code>package.json</code> to force safe transitive dependency versions: <ul><li><code>picomatch</code> → <code>^4.0.4</code> (fixes ReDoS + method injection CVEs)</li><li><code>flatted</code> → <code>^3.4.2</code> (fixes unbounded recursion DoS + prototype pollution)</li><li><code>brace-expansion</code> → <code>^5.0.5</code> (fixes zero-step sequence memory exhaustion)</li></ul></li><li><strong>Result:</strong> <code>npm audit</code> now reports <strong>0 vulnerabilities</strong> (down from 13: 3 critical, 4 high, 3 moderate, 3 low)</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>CORS is now <strong>restricted</strong> — previously <code>app.use(cors())</code> allowed all origins; now uses an allowlist via <code>ALLOWED_ORIGINS</code> environment variable (comma-separated). Defaults to localhost development origins</li><li>API rate limiting is now <strong>tiered</strong>: <ul><li><code>globalApiRateLimiter</code> — 100 req/min applied to all <code>/api/*</code></li><li><code>adminApiRateLimiter</code> — 60 req/min applied to admin routes (routes, webhooks, settings, logs, metrics, AI, troubleshooting)</li><li><code>authRateLimiter</code> — 5 req/15min on <code>/api/auth</code> to prevent brute-force attacks</li></ul></li></ul><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>New API routes registered in <code>app.ts</code>: <ul><li><code>GET|PUT|POST /api/settings</code> — general settings management with validation, sanitization and backup</li><li><code>GET|PUT /api/settings/ai</code> — AI provider configuration</li><li><code>GET|PUT /api/settings/claude</code> — Claude-specific settings</li><li><code>GET|POST /api/ai</code> — AI analysis endpoints</li><li><code>GET|POST|PUT|DELETE /api/ai-incidents</code> — AI incident tracking</li></ul></li></ul><hr><h2 id="_0-1-0-beta-1-2026-02-04" tabindex="-1">[0.1.0-beta.1] - 2026-02-04 <a class="header-anchor" href="#_0-1-0-beta-1-2026-02-04" aria-label="Permalink to &quot;[0.1.0-beta.1] - 2026-02-04&quot;">​</a></h2><h3 id="🎉-first-public-beta-release" tabindex="-1">🎉 First Public Beta Release <a class="header-anchor" href="#🎉-first-public-beta-release" aria-label="Permalink to &quot;🎉 First Public Beta Release&quot;">​</a></h3><p>This is the initial beta release of FlexGate Proxy available on npm!</p><p><strong>⚠️ Beta Status</strong>: Not recommended for production use. Please report issues on GitHub.</p><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><h4 id="npm-package-cli" tabindex="-1">NPM Package &amp; CLI <a class="header-anchor" href="#npm-package-cli" aria-label="Permalink to &quot;NPM Package &amp; CLI&quot;">​</a></h4><ul><li><strong>NPM Package</strong>: Published as <code>flexgate-proxy</code> on npm registry</li><li><strong>CLI Tool</strong>: <code>flexgate</code> command for easy management <ul><li><code>flexgate start</code> - Start the gateway</li><li><code>flexgate init</code> - Generate configuration file</li><li><code>flexgate migrate</code> - Run database migrations</li><li><code>flexgate status</code> - Check health status</li></ul></li><li><strong>Programmatic API</strong>: Use as a library in Node.js applications</li><li><strong>Post-Install Guide</strong>: Helpful welcome message and quick start</li><li><strong>TypeScript Definitions</strong>: Full .d.ts files included</li></ul><h4 id="developer-experience" tabindex="-1">Developer Experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to &quot;Developer Experience&quot;">​</a></h4><ul><li><strong>QUICK_START.md</strong>: Get started in 5 minutes guide</li><li><strong>Beta Release Checklist</strong>: Complete release process documentation</li><li><strong>Examples</strong>: Common use case examples</li><li><strong>Automated Security</strong>: Dependabot + CodeQL configured</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Version</strong>: Set to 0.1.0-beta.1 for initial beta release</li><li><strong>Package Metadata</strong>: Updated author, repository, and npm configuration</li><li><strong>Build Output</strong>: Optimized dist/ folder for npm distribution</li></ul><h3 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h3><ul><li>Admin UI requires separate build step</li><li>Limited test coverage in some areas</li><li>Performance not yet optimized for high load</li><li>Some advanced features still in development</li></ul><h3 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h3><ul><li>@tapas100</li></ul><hr><h2 id="_1-0-0-2026-01-26" tabindex="-1"><a href="https://github.com/tapas100/flexgate-proxy/releases/tag/v1.0.0" target="_blank" rel="noreferrer">1.0.0</a> - 2026-01-26 <a class="header-anchor" href="#_1-0-0-2026-01-26" aria-label="Permalink to &quot;[1.0.0] - 2026-01-26&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><p><strong>Core proxy functionality</strong></p><ul><li>HTTP/HTTPS request proxying</li><li>Streaming large responses</li><li>Connection pooling</li></ul></li><li><p><strong>Security</strong></p><ul><li>SSRF protection (IP blacklist, host allowlist)</li><li>Header sanitization</li><li>Request/response size limits</li><li>API key authentication (HMAC-SHA256)</li></ul></li><li><p><strong>Reliability</strong></p><ul><li>Circuit breaker pattern per upstream</li><li>Exponential backoff retries with jitter</li><li>Request/connection/DNS timeouts</li><li>Graceful degradation under load</li></ul></li><li><p><strong>Rate Limiting</strong></p><ul><li>Token bucket algorithm</li><li>Redis-backed distributed rate limiting</li><li>Fallback to local rate limiting</li><li>Per-route configuration</li></ul></li><li><p><strong>Observability</strong></p><ul><li>Structured JSON logging with correlation IDs</li><li>Prometheus metrics (RPS, latency, errors)</li><li>Health check endpoints (live, ready, deep)</li><li>Log sampling (configurable)</li></ul></li><li><p><strong>Configuration</strong></p><ul><li>YAML-based config</li><li>Hot reload support</li><li>Per-route overrides</li><li>Environment variable support</li></ul></li><li><p><strong>Deployment</strong></p><ul><li>Docker support with multi-stage build</li><li>Kubernetes manifests (Deployment, Service, HPA, PDB)</li><li>Docker Compose for local dev</li><li>Prometheus/Grafana stack</li></ul></li><li><p><strong>Documentation</strong></p><ul><li>Comprehensive README</li><li>Threat model analysis</li><li>Observability guide</li><li>Traffic control patterns</li><li>Architectural trade-offs</li><li>Benchmark results</li></ul></li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>SSRF protection against cloud metadata endpoints</li><li>Deny-by-default security posture</li><li>Input validation and sanitization</li></ul><h2 id="unreleased-1" tabindex="-1">[Unreleased] <a class="header-anchor" href="#unreleased-1" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h3 id="planned" tabindex="-1">Planned <a class="header-anchor" href="#planned" aria-label="Permalink to &quot;Planned&quot;">​</a></h3><ul><li>mTLS support for upstream connections</li><li>OpenTelemetry distributed tracing</li><li>GraphQL federation support</li><li>Admin UI for configuration management</li><li>gRPC proxying</li><li>WebAssembly plugin system</li></ul><hr>',37)])])}const g=i(l,[["render",r]]);export{p as __pageData,g as default};
